// [=]===^=[ ed_find_widget ]=====================================[=]
static int32_t ed_find_widget(uint32_t id) {
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].id == id) {
			return (int32_t)i;
		}
	}
	return -1;
}

// [=]===^=[ ed_gen_id_name ]=====================================[=]
static void ed_gen_id_name(struct ed_widget *w) {
	const char *prefix = "ID";
	switch(w->type) {
		case MKGUI_WINDOW:     { prefix = "ID_WINDOW"; } break;
		case MKGUI_BUTTON:     { prefix = "ID_BUTTON"; } break;
		case MKGUI_LABEL:      { prefix = "ID_LABEL"; } break;
		case MKGUI_INPUT:      { prefix = "ID_INPUT"; } break;
		case MKGUI_CHECKBOX:   { prefix = "ID_CHECK"; } break;
		case MKGUI_DROPDOWN:   { prefix = "ID_DROPDOWN"; } break;
		case MKGUI_SLIDER:     { prefix = "ID_SLIDER"; } break;
		case MKGUI_LISTVIEW:   { prefix = "ID_LISTVIEW"; } break;
		case MKGUI_TABS:       { prefix = "ID_TABS"; } break;
		case MKGUI_TAB:        { prefix = "ID_TAB"; } break;
		case MKGUI_HSPLIT: { prefix = "ID_SPLITH"; } break;
		case MKGUI_VSPLIT: { prefix = "ID_SPLITV"; } break;
		case MKGUI_TREEVIEW:   { prefix = "ID_TREEVIEW"; } break;
		case MKGUI_MENU:       { prefix = "ID_MENU"; } break;
		case MKGUI_MENUITEM:   { prefix = "ID_MENUITEM"; } break;
		case MKGUI_STATUSBAR:  { prefix = "ID_STATUSBAR"; } break;
		case MKGUI_TOOLBAR:    { prefix = "ID_TOOLBAR"; } break;
		case MKGUI_RADIO:      { prefix = "ID_RADIO"; } break;
		case MKGUI_PROGRESS:   { prefix = "ID_PROGRESS"; } break;
		case MKGUI_TEXTAREA:   { prefix = "ID_TEXTAREA"; } break;
		case MKGUI_SPINBOX:    { prefix = "ID_SPINBOX"; } break;
		case MKGUI_GROUP:      { prefix = "ID_GROUP"; } break;
		case MKGUI_SPINNER:    { prefix = "ID_SPINNER"; } break;
		case MKGUI_ITEMVIEW:   { prefix = "ID_ITEMVIEW"; } break;
		case MKGUI_PANEL:      { prefix = "ID_PANEL"; } break;
		case MKGUI_SCROLLBAR:  { prefix = "ID_SCROLLBAR"; } break;
		case MKGUI_IMAGE:      { prefix = "ID_IMAGE"; } break;
		case MKGUI_GLVIEW:     { prefix = "ID_GLVIEW"; } break;
		case MKGUI_CANVAS:     { prefix = "ID_CANVAS"; } break;
		case MKGUI_VBOX:       { prefix = "ID_VBOX"; } break;
		case MKGUI_HBOX:       { prefix = "ID_HBOX"; } break;
		case MKGUI_FORM:       { prefix = "ID_FORM"; } break;
		default: break;
	}
	snprintf(w->id_name, sizeof(w->id_name), "%s_%u", prefix, w->id);
}

// [=]===^=[ ed_add_widget ]======================================[=]
static int32_t ed_add_widget(uint32_t type, int32_t x, int32_t y) {
	if(ed.widget_count >= ED_MAX_WIDGETS) {
		return -1;
	}

	ed_push_undo();

	struct ed_widget *w = &ed.widgets[ed.widget_count];
	memset(w, 0, sizeof(*w));
	w->type = type;
	w->id = ed.next_id++;
	w->x = x;
	w->y = y;

	switch(type) {
		case MKGUI_WINDOW: {
			w->w = ED_CANVAS_DEF_W;
			w->h = ED_CANVAS_DEF_H;
			snprintf(w->label, sizeof(w->label), "Window");
		} break;

		case MKGUI_BUTTON: {
			w->w = 80;
			w->h = 28;
			snprintf(w->label, sizeof(w->label), "Button");
		} break;

		case MKGUI_LABEL: {
			w->w = 80;
			w->h = 20;
			snprintf(w->label, sizeof(w->label), "Label");
		} break;

		case MKGUI_INPUT: {
			w->w = 150;
			w->h = 24;
		} break;

		case MKGUI_CHECKBOX: {
			w->w = 120;
			w->h = 20;
			snprintf(w->label, sizeof(w->label), "Checkbox");
		} break;

		case MKGUI_DROPDOWN: {
			w->w = 150;
			w->h = 24;
		} break;

		case MKGUI_SLIDER: {
			w->w = 200;
			w->h = 20;
			snprintf(w->label, sizeof(w->label), "Slider");
		} break;

		case MKGUI_LISTVIEW: {
			w->w = 300;
			w->h = 200;
		} break;

		case MKGUI_TABS: {
			w->w = 300;
			w->h = 200;
		} break;

		case MKGUI_TAB: {
			w->w = 0;
			w->h = 0;
			snprintf(w->label, sizeof(w->label), "Tab");
		} break;

		case MKGUI_HSPLIT:
		case MKGUI_VSPLIT: {
			w->w = 300;
			w->h = 200;
		} break;

		case MKGUI_TREEVIEW: {
			w->w = 200;
			w->h = 200;
		} break;

		case MKGUI_MENU: {
			w->x = 0;
			w->y = 0;
			w->w = ed.canvas_w;
			w->h = MKGUI_MENU_HEIGHT;
			w->flags = MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_TOP | MKGUI_ANCHOR_RIGHT;
		} break;

		case MKGUI_MENUITEM: {
			snprintf(w->label, sizeof(w->label), "Item");
		} break;

		case MKGUI_STATUSBAR: {
			w->x = 0;
			w->y = ed.canvas_h - MKGUI_STATUSBAR_HEIGHT;
			w->w = ed.canvas_w;
			w->h = MKGUI_STATUSBAR_HEIGHT;
			w->flags = MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_BOTTOM | MKGUI_ANCHOR_RIGHT;
		} break;

		case MKGUI_TOOLBAR: {
			w->x = 0;
			w->y = 0;
			for(uint32_t j = 0; j < ed.widget_count; ++j) {
				if(ed.widgets[j].type == MKGUI_MENU && ed.widgets[j].parent_id == ed.widgets[0].id) {
					w->y = ed.widgets[j].y + ed.widgets[j].h;
					break;
				}
			}
			w->w = ed.canvas_w;
			w->h = MKGUI_TOOLBAR_HEIGHT;
			w->flags = MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_TOP | MKGUI_ANCHOR_RIGHT;
		} break;

		case MKGUI_RADIO: {
			w->w = 120;
			w->h = 20;
			snprintf(w->label, sizeof(w->label), "Radio");
		} break;

		case MKGUI_PROGRESS: {
			w->w = 200;
			w->h = 20;
		} break;

		case MKGUI_TEXTAREA: {
			w->w = 200;
			w->h = 100;
		} break;

		case MKGUI_SPINBOX: {
			w->w = 100;
			w->h = 24;
		} break;

		case MKGUI_GROUP: {
			w->w = 300;
			w->h = 150;
			snprintf(w->label, sizeof(w->label), "Group");
		} break;

		case MKGUI_SPINNER: {
			w->w = 28;
			w->h = 28;
		} break;

		case MKGUI_ITEMVIEW: {
			w->w = 300;
			w->h = 200;
		} break;

		case MKGUI_PANEL: {
			w->w = 300;
			w->h = 200;
		} break;

		case MKGUI_SCROLLBAR: {
			w->w = MKGUI_SCROLLBAR_W;
			w->h = 200;
		} break;

		case MKGUI_IMAGE: {
			w->w = 200;
			w->h = 150;
		} break;

		case MKGUI_GLVIEW: {
			w->w = 300;
			w->h = 200;
		} break;

		case MKGUI_CANVAS: {
			w->w = 200;
			w->h = 150;
		} break;

		case MKGUI_HBOX: {
			w->x = 0;
			w->y = 0;
			w->w = ed.canvas_w;
			w->h = ed.canvas_h;
			w->flags = MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_TOP | MKGUI_ANCHOR_RIGHT | MKGUI_ANCHOR_BOTTOM;
		} break;

		case MKGUI_VBOX: {
			w->x = 0;
			w->y = 0;
			w->w = ed.canvas_w;
			w->h = ed.canvas_h;
			w->flags = MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_TOP | MKGUI_ANCHOR_RIGHT | MKGUI_ANCHOR_BOTTOM;
		} break;

		case MKGUI_FORM: {
			w->x = 0;
			w->w = ed.canvas_w;
			w->h = 200;
			w->flags = MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_RIGHT;
		} break;

		default: {
			w->w = 100;
			w->h = 30;
		} break;
	}

	w->tab_order = ed.widget_count;
	ed_gen_id_name(w);

	if(ed.widget_count > 0 && type != MKGUI_WINDOW) {
		w->parent_id = ed.widgets[0].id;
	}

	++ed.widget_count;
	int32_t result = (int32_t)(ed.widget_count - 1);

	if(type == MKGUI_TABS && ed.widget_count < ED_MAX_WIDGETS) {
		uint32_t tabs_id = w->id;
		struct ed_widget *tab = &ed.widgets[ed.widget_count];
		memset(tab, 0, sizeof(*tab));
		tab->type = MKGUI_TAB;
		tab->id = ed.next_id++;
		tab->parent_id = tabs_id;
		snprintf(tab->label, sizeof(tab->label), "Tab 1");
		tab->tab_order = ed.widget_count;
		ed_gen_id_name(tab);
		++ed.widget_count;
		ed_set_active_tab(tabs_id, tab->id);
	}

	if(type == MKGUI_MENU && ed.widget_count < ED_MAX_WIDGETS) {
		uint32_t menu_id = w->id;
		struct ed_widget *item = &ed.widgets[ed.widget_count];
		memset(item, 0, sizeof(*item));
		item->type = MKGUI_MENUITEM;
		item->id = ed.next_id++;
		item->parent_id = menu_id;
		snprintf(item->label, sizeof(item->label), "File");
		item->tab_order = ed.widget_count;
		ed_gen_id_name(item);
		++ed.widget_count;
	}

	return result;
}

// [=]===^=[ ed_is_descendant ]====================================[=]
static uint32_t ed_is_descendant(uint32_t widget_idx, uint32_t ancestor_id) {
	uint32_t pid = ed.widgets[widget_idx].parent_id;
	for(uint32_t depth = 0; depth < 32; ++depth) {
		if(pid == ancestor_id) {
			return 1;
		}
		if(pid == 0) {
			return 0;
		}
		uint32_t found = 0;
		for(uint32_t j = 0; j < ed.widget_count; ++j) {
			if(ed.widgets[j].id == pid) {
				pid = ed.widgets[j].parent_id;
				found = 1;
				break;
			}
		}
		if(!found) {
			return 0;
		}
	}
	return 0;
}

// [=]===^=[ ed_delete_widget_tree ]===============================[=]
static void ed_delete_widget_tree(uint32_t id) {
	for(uint32_t i = ed.widget_count; i > 0; --i) {
		uint32_t idx = i - 1;
		if(ed_is_descendant(idx, id)) {
			memmove(&ed.widgets[idx], &ed.widgets[idx + 1], (ed.widget_count - idx - 1) * sizeof(struct ed_widget));
			--ed.widget_count;
		}
	}
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].id == id) {
			memmove(&ed.widgets[i], &ed.widgets[i + 1], (ed.widget_count - i - 1) * sizeof(struct ed_widget));
			--ed.widget_count;
			break;
		}
	}
}

// [=]===^=[ ed_delete_selected ]=================================[=]
static void ed_delete_selected(void) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}
	if(ed.widgets[ed.selected].type == MKGUI_WINDOW) {
		return;
	}
	ed_push_undo();
	uint32_t del_id = ed.widgets[ed.selected].id;
	uint32_t del_parent = ed.widgets[ed.selected].parent_id;
	int32_t next_sel = -1;
	for(int32_t i = ed.selected + 1; (uint32_t)i < ed.widget_count; ++i) {
		if(ed.widgets[i].parent_id == del_parent && !ed_is_descendant((uint32_t)i, del_id)) {
			next_sel = (int32_t)ed.widgets[i].id;
			break;
		}
	}
	if(next_sel < 0) {
		for(int32_t i = ed.selected - 1; i >= 0; --i) {
			if(ed.widgets[i].parent_id == del_parent && ed.widgets[i].id != del_id) {
				next_sel = (int32_t)ed.widgets[i].id;
				break;
			}
		}
	}
	if(next_sel < 0) {
		next_sel = (int32_t)del_parent;
	}
	ed_delete_widget_tree(del_id);
	ed.selected = ed_find_widget((uint32_t)next_sel);
}

// [=]===^=[ ed_insert_child_after ]================================[=]
static uint32_t ed_insert_child_after(uint32_t parent_id) {
	if(ed.widget_count >= ED_MAX_WIDGETS) {
		return ed.widget_count;
	}
	uint32_t insert_at = ed.widget_count;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].id == parent_id) {
			insert_at = i + 1;
			for(uint32_t j = insert_at; j < ed.widget_count; ++j) {
				if(ed_is_descendant(j, parent_id)) {
					insert_at = j + 1;
				}
			}
			break;
		}
	}
	if(insert_at < ed.widget_count) {
		memmove(&ed.widgets[insert_at + 1], &ed.widgets[insert_at], (ed.widget_count - insert_at) * sizeof(struct ed_widget));
	}
	memset(&ed.widgets[insert_at], 0, sizeof(struct ed_widget));
	++ed.widget_count;
	return insert_at;
}

// [=]===^=[ ed_widget_canvas_pos ]================================[=]
static void ed_widget_canvas_pos(uint32_t idx, int32_t *out_x, int32_t *out_y) {
	struct ed_widget *w = &ed.widgets[idx];
	if(w->type == MKGUI_TAB) {
		for(uint32_t j = 0; j < ed.widget_count; ++j) {
			if(ed.widgets[j].id == w->parent_id) {
				*out_x = ed.widgets[j].x;
				*out_y = ed.widgets[j].y + MKGUI_TAB_HEIGHT;
				return;
			}
		}
	}
	*out_x = w->x;
	*out_y = w->y;
}

// [=]===^=[ ed_convert_to_layout ]================================[=]
static void ed_convert_to_layout(uint32_t idx, int32_t *lx, int32_t *ly, int32_t *lw, int32_t *lh) {
	struct ed_widget *ew = &ed.widgets[idx];
	int32_t px = 0, py = 0, pw = 0, ph = 0;
	uint32_t parent_type = 0;
	for(uint32_t j = 0; j < ed.widget_count; ++j) {
		if(ed.widgets[j].id == ew->parent_id) {
			ed_widget_canvas_pos(j, &px, &py);
			pw = ed.widgets[j].w;
			ph = ed.widgets[j].h;
			parent_type = ed.widgets[j].type;
			break;
		}
	}

	int32_t rel_x = ew->x - px;
	int32_t rel_y = ew->y - py;
	int32_t w = ew->w;
	int32_t h = ew->h;
	uint32_t flags = ew->flags;

	if(parent_type == MKGUI_VBOX || parent_type == MKGUI_HBOX || parent_type == MKGUI_FORM) {
		*lx = rel_x;
		*ly = rel_y;
		*lw = w;
		*lh = h;
		return;
	}

	if((flags & MKGUI_ANCHOR_LEFT) && (flags & MKGUI_ANCHOR_RIGHT)) {
		w = pw - rel_x - w;
		if(w < 0) {
			w = 0;
		}

	} else if(flags & MKGUI_ANCHOR_RIGHT) {
		rel_x = pw - rel_x - w;
	}

	if((flags & MKGUI_ANCHOR_TOP) && (flags & MKGUI_ANCHOR_BOTTOM)) {
		h = ph - rel_y - h;
		if(h < 0) {
			h = 0;
		}

	} else if(flags & MKGUI_ANCHOR_BOTTOM) {
		rel_y = ph - rel_y - h;
	}

	*lx = rel_x;
	*ly = rel_y;
	*lw = w;
	*lh = h;
}

// ---------------------------------------------------------------------------
// Design-time widget rects (computed each frame by ed_render_canvas)
// ---------------------------------------------------------------------------

static struct { int32_t x, y, w, h; } ed_rects[ED_MAX_WIDGETS];
static int32_t ed_win_x, ed_win_y;

// [=]===^=[ ed_tab_header_hit ]===================================[=]
static uint32_t ed_tab_header_hit(struct mkgui_ctx *ctx, int32_t tabs_idx, int32_t lx, int32_t ly) {
	int32_t sx = lx + ed_win_x;
	int32_t sy = ly + ed_win_y;
	int32_t rel_x = sx - ed_rects[tabs_idx].x;
	int32_t rel_y = sy - ed_rects[tabs_idx].y;
	if(rel_y < 0 || rel_y >= MKGUI_TAB_HEIGHT) {
		return 0;
	}
	struct ed_widget *tabs_w = &ed.widgets[tabs_idx];
	int32_t tab_x = 0;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_TAB && ed.widgets[i].parent_id == tabs_w->id) {
			int32_t tw = text_width(ctx, ed.widgets[i].label) + 20;
			if(rel_x >= tab_x && rel_x < tab_x + tw) {
				return ed.widgets[i].id;
			}
			tab_x += tw;
		}
	}
	return 0;
}

// [=]===^=[ ed_snap ]============================================[=]
static int32_t ed_snap(int32_t v) {
	if(ed.grid_size <= 1) {
		return v;
	}
	return ((v + ed.grid_size / 2) / ed.grid_size) * ed.grid_size;
}

// [=]===^=[ ed_canvas_hit ]======================================[=]
static int32_t ed_canvas_hit(int32_t lx, int32_t ly) {
	int32_t sx = lx + ed_win_x;
	int32_t sy = ly + ed_win_y;
	for(int32_t i = (int32_t)ed.widget_count - 1; i >= 0; --i) {
		struct ed_widget *w = &ed.widgets[i];
		if(w->type == MKGUI_WINDOW || w->type == MKGUI_TAB || w->type == MKGUI_MENUITEM) {
			continue;
		}
		if(!ed_is_tab_child_visible((uint32_t)i)) {
			continue;
		}
		if(ed_rects[i].w <= 0 || ed_rects[i].h <= 0) {
			continue;
		}
		if(sx >= ed_rects[i].x && sx < ed_rects[i].x + ed_rects[i].w && sy >= ed_rects[i].y && sy < ed_rects[i].y + ed_rects[i].h) {
			return i;
		}
	}
	return -1;
}

// [=]===^=[ ed_handle_hit ]======================================[=]
static int32_t ed_handle_hit(int32_t lx, int32_t ly) {
	if(ed.selected < 0) {
		return -1;
	}
	int32_t sx = lx + ed_win_x;
	int32_t sy = ly + ed_win_y;
	int32_t wx = ed_rects[ed.selected].x;
	int32_t wy = ed_rects[ed.selected].y;
	int32_t ww = ed_rects[ed.selected].w;
	int32_t wh = ed_rects[ed.selected].h;
	int32_t hx[] = { wx, wx + ww / 2, wx + ww, wx + ww, wx + ww, wx + ww / 2, wx, wx };
	int32_t hy[] = { wy, wy, wy, wy + wh / 2, wy + wh, wy + wh, wy + wh, wy + wh / 2 };
	for(int32_t i = 0; i < 8; ++i) {
		if(sx >= hx[i] - 4 && sx <= hx[i] + 4 && sy >= hy[i] - 4 && sy <= hy[i] + 4) {
			return i;
		}
	}
	return -1;
}

#define ED_EDGE_LEFT   1
#define ED_EDGE_TOP    2
#define ED_EDGE_RIGHT  4
#define ED_EDGE_BOTTOM 8
#define ED_CANVAS_MIN  64
#define ED_EDGE_THRESH 5

// [=]===^=[ ed_canvas_edge_hit ]==================================[=]
static uint32_t ed_canvas_edge_hit(int32_t lx, int32_t ly) {
	uint32_t edges = 0;
	int32_t cw = ed.canvas_w;
	int32_t ch = ed.canvas_h;
	int32_t t = ED_EDGE_THRESH;

	if(lx >= -t && lx <= t && ly >= -t && ly <= ch + t) {
		edges |= ED_EDGE_LEFT;
	}
	if(lx >= cw - t && lx <= cw + t && ly >= -t && ly <= ch + t) {
		edges |= ED_EDGE_RIGHT;
	}
	if(ly >= -t && ly <= t && lx >= -t && lx <= cw + t) {
		edges |= ED_EDGE_TOP;
	}
	if(ly >= ch - t && ly <= ch + t && lx >= -t && lx <= cw + t) {
		edges |= ED_EDGE_BOTTOM;
	}
	return edges;
}

// ---------------------------------------------------------------------------
// Design-time widget drawing (inert visual representations)
// ---------------------------------------------------------------------------

// [=]===^=[ ed_draw_widget ]======================================[=]
static void ed_draw_widget(struct mkgui_ctx *ctx, uint32_t idx) {
	struct ed_widget *ew = &ed.widgets[idx];
	int32_t rx = ed_rects[idx].x;
	int32_t ry = ed_rects[idx].y;
	int32_t rw = ed_rects[idx].w;
	int32_t rh = ed_rects[idx].h;
	uint32_t *buf = ctx->pixels;
	int32_t bw = ctx->win_w;
	int32_t bh = ctx->win_h;

	switch(ew->type) {
		case MKGUI_BUTTON: {
			draw_patch(ctx, MKGUI_STYLE_RAISED, rx, ry, rw, rh, ctx->theme.widget_bg, ctx->theme.widget_border);
			int32_t icon_idx = ew->icon[0] ? icon_resolve(ew->icon) : -1;
			int32_t icon_w = icon_idx >= 0 ? MKGUI_ICON_SIZE + 4 : 0;
			int32_t tw = text_width(ctx, ew->label);
			int32_t content_w = icon_w + (ew->label[0] ? tw : 0);
			int32_t cx = rx + (rw - content_w) / 2;
			if(icon_idx >= 0) {
				int32_t iy = ry + (rh - MKGUI_ICON_SIZE) / 2;
				draw_icon(buf, bw, bh, &icons[icon_idx], cx, iy, rx, ry, rx + rw, ry + rh);
				cx += MKGUI_ICON_SIZE + 4;
			}
			if(ew->label[0]) {
				int32_t ty = ry + (rh - ctx->font_height) / 2;
				push_text_clip(cx, ty, ew->label, ctx->theme.text, rx, ry, rx + rw, ry + rh);
			}
		} break;

		case MKGUI_LABEL: {
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx, ty, ew->label, ctx->theme.text, rx, ry, rx + rw, ry + rh);
		} break;

		case MKGUI_INPUT: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			if(ew->label[0]) {
				int32_t ty = ry + (rh - ctx->font_height) / 2;
				push_text_clip(rx + 4, ty, ew->label, ctx->theme.text_disabled, rx + 1, ry + 1, rx + rw - 1, ry + rh - 1);
			}
		} break;

		case MKGUI_CHECKBOX: {
			int32_t box_size = 16;
			int32_t by = ry + (rh - box_size) / 2;
			uint32_t bg = (ew->flags & MKGUI_CHECKED) ? ctx->theme.splitter : ctx->theme.input_bg;
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, by, box_size, box_size, bg, ctx->theme.widget_border);
			if(ew->flags & MKGUI_CHECKED) {
				int32_t cx = rx + box_size / 2;
				int32_t cy = by + box_size / 2;
				draw_aa_line(buf, bw, bh, cx - 4, cy - 1, cx - 1, cy + 3, ctx->theme.sel_text, 2);
				draw_aa_line(buf, bw, bh, cx - 1, cy + 3, cx + 5, cy - 4, ctx->theme.sel_text, 2);
			}
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + box_size + 6, ty, ew->label, ctx->theme.text, rx, ry, rx + rw, ry + rh);
		} break;

		case MKGUI_RADIO: {
			int32_t cy = ry + rh / 2;
			int32_t cx = rx + 9;
			uint32_t fill = (ew->flags & MKGUI_CHECKED) ? ctx->theme.splitter : ctx->theme.input_bg;
			draw_aa_circle_ring(buf, bw, bh, cx, cy, 7, 6, fill, ctx->theme.widget_border);
			if(ew->flags & MKGUI_CHECKED) {
				draw_aa_circle_fill(buf, bw, bh, cx, cy, 3, ctx->theme.sel_text);
			}
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 22, ty, ew->label, ctx->theme.text, rx, ry, rx + rw, ry + rh);
		} break;

		case MKGUI_SLIDER: {
			int32_t track_y = ry + rh / 2 - 2;
			draw_rounded_rect_fill(buf, bw, bh, rx, track_y, rw, 4, ctx->theme.widget_border, 2);
			int32_t thumb_x = rx + rw / 3;
			draw_patch(ctx, MKGUI_STYLE_RAISED, thumb_x, ry + 2, 10, rh - 4, ctx->theme.splitter, ctx->theme.splitter);
			if(ew->label[0]) {
				int32_t ty = ry - ctx->font_height - 2;
				if(ty >= 0) {
					push_text_clip(rx, ty, ew->label, ctx->theme.text, rx, ty, rx + rw, ry + rh);
				}
			}
		} break;

		case MKGUI_DROPDOWN: {
			draw_patch(ctx, MKGUI_STYLE_RAISED, rx, ry, rw, rh, ctx->theme.widget_bg, ctx->theme.widget_border);
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 4, ty, ew->label, ctx->theme.text, rx + 1, ry + 1, rx + rw - 16, ry + rh - 1);
			int32_t ax = rx + rw - 14;
			int32_t ay = ry + rh / 2 - 2;
			for(int32_t j = 0; j < 5; ++j) {
				draw_hline(buf, bw, bh, ax + j, ay + j, 9 - j * 2, ctx->theme.text);
			}
		} break;

		case MKGUI_SPINBOX: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			if(ew->label[0]) {
				int32_t ty = ry + (rh - ctx->font_height) / 2;
				push_text_clip(rx + 4, ty, ew->label, ctx->theme.text_disabled, rx + 1, ry + 1, rx + rw - 20, ry + rh - 1);
			}
			int32_t bx = rx + rw - 20;
			int32_t half = rh / 2;
			draw_patch(ctx, MKGUI_STYLE_RAISED, bx, ry, 20, half, ctx->theme.widget_bg, ctx->theme.widget_border);
			draw_patch(ctx, MKGUI_STYLE_RAISED, bx, ry + half, 20, rh - half, ctx->theme.widget_bg, ctx->theme.widget_border);
			int32_t ac = bx + 10;
			for(int32_t j = 0; j < 3; ++j) {
				draw_hline(buf, bw, bh, ac - j, ry + half / 2 - j, j * 2 + 1, ctx->theme.text);
			}
			for(int32_t j = 0; j < 3; ++j) {
				draw_hline(buf, bw, bh, ac - j, ry + half + (rh - half) / 2 + j, j * 2 + 1, ctx->theme.text);
			}
		} break;

		case MKGUI_PROGRESS: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			int32_t fill_w = (rw - 2) / 2;
			int32_t fill_r = ctx->theme.corner_radius > 1 ? ctx->theme.corner_radius - 1 : 0;
			draw_rounded_rect_fill(buf, bw, bh, rx + 1, ry + 1, fill_w, rh - 2, ctx->theme.accent, fill_r);
		} break;

		case MKGUI_TABS: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, MKGUI_TAB_HEIGHT, ctx->theme.tab_inactive);
			uint32_t active_id = ed_get_active_tab(ew->id);
			int32_t tx = rx;
			for(uint32_t i = 0; i < ed.widget_count; ++i) {
				struct ed_widget *child = &ed.widgets[i];
				if(child->type != MKGUI_TAB || child->parent_id != ew->id) {
					continue;
				}
				int32_t tw = text_width(ctx, child->label) + 20;
				uint32_t active = (child->id == active_id);
				uint32_t tab_bg = active ? ctx->theme.tab_active : ctx->theme.tab_inactive;
				uint32_t bd = active ? ctx->theme.widget_border : ctx->theme.tab_inactive;
				draw_rounded_rect(buf, bw, bh, tx, ry, tw, MKGUI_TAB_HEIGHT, tab_bg, bd, ctx->theme.corner_radius);
				if(active) {
					draw_hline(buf, bw, bh, tx, ry, tw, ctx->theme.splitter);
				}
				int32_t tty = ry + (MKGUI_TAB_HEIGHT - ctx->font_height) / 2;
				push_text_clip(tx + 10, tty, child->label, ctx->theme.text, tx, ry, tx + tw, ry + MKGUI_TAB_HEIGHT);
				tx += tw;
			}
			draw_hline(buf, bw, bh, rx, ry + MKGUI_TAB_HEIGHT - 1, rw, ctx->theme.widget_border);
		} break;

		case MKGUI_GROUP: {
			int32_t label_y = ry + 2;
			int32_t label_x = rx + 10;
			int32_t tw = text_width(ctx, ew->label);
			int32_t gap_left = label_x - 4;
			int32_t gap_right = label_x + tw + 4;
			int32_t frame_y = ry + ctx->font_height / 2 + 2;
			int32_t frame_h = rh - (frame_y - ry);
			uint32_t group_bg = shade_color(ctx->theme.bg, -10);
			draw_rounded_rect(buf, bw, bh, rx, frame_y, rw, frame_h, group_bg, ctx->theme.widget_border, ctx->theme.corner_radius);
			if(gap_left > rx && gap_right <= rx + rw) {
				if(frame_y >= 0 && frame_y < bh) {
					int32_t left = gap_left < 0 ? 0 : gap_left;
					int32_t right = gap_right > bw ? bw : gap_right;
					uint32_t *row = &buf[frame_y * bw];
					for(int32_t x = left; x < right; ++x) {
						row[x] = group_bg;
					}
				}
			}
			push_text_clip(label_x, label_y, ew->label, ctx->theme.text, rx, ry, rx + rw, ry + rh);
		} break;

		case MKGUI_PANEL:
		case MKGUI_VBOX:
		case MKGUI_HBOX:
		case MKGUI_FORM: {
			uint32_t bg = (ew->flags & MKGUI_PANEL_SUNKEN) ? shade_color(ctx->theme.bg, -15) : ctx->theme.bg;
			if(ew->flags & MKGUI_PANEL_BORDER) {
				draw_rounded_rect(buf, bw, bh, rx, ry, rw, rh, bg, ctx->theme.widget_border, ctx->theme.corner_radius);
			}
		} break;

		case MKGUI_LISTVIEW: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			draw_rect_fill(buf, bw, bh, rx + 1, ry + 1, rw - 2, MKGUI_ROW_HEIGHT, ctx->theme.header_bg);
			draw_hline(buf, bw, bh, rx + 1, ry + MKGUI_ROW_HEIGHT, rw - 2, ctx->theme.widget_border);
			int32_t ty = ry + (MKGUI_ROW_HEIGHT - ctx->font_height) / 2 + 1;
			push_text_clip(rx + 4, ty, ew->label[0] ? ew->label : "ListView", ctx->theme.text, rx + 1, ry + 1, rx + rw - 1, ry + MKGUI_ROW_HEIGHT);
		} break;

		case MKGUI_TREEVIEW: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 4, ty, ew->label[0] ? ew->label : "TreeView", ctx->theme.text_disabled, rx + 1, ry + 1, rx + rw - 1, ry + rh - 1);
		} break;

		case MKGUI_TEXTAREA: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			if(ew->label[0]) {
				int32_t ty = ry + 2;
				push_text_clip(rx + 4, ty, ew->label, ctx->theme.text_disabled, rx + 1, ry + 1, rx + rw - 1, ry + rh - 1);
			}
		} break;

		case MKGUI_ITEMVIEW: {
			draw_patch(ctx, MKGUI_STYLE_SUNKEN, rx, ry, rw, rh, ctx->theme.input_bg, ctx->theme.widget_border);
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 4, ty, ew->label[0] ? ew->label : "ItemView", ctx->theme.text_disabled, rx + 1, ry + 1, rx + rw - 1, ry + rh - 1);
		} break;

		case MKGUI_TOOLBAR: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, ctx->theme.header_bg);
			draw_hline(buf, bw, bh, rx, ry + rh - 1, rw, ctx->theme.widget_border);
			int32_t bx = rx + 2;
			for(uint32_t i = 0; i < ed.widget_count; ++i) {
				struct ed_widget *btn = &ed.widgets[i];
				if(btn->type != MKGUI_BUTTON || btn->parent_id != ew->id) {
					continue;
				}
				if(btn->flags & MKGUI_TOOLBAR_SEP) {
					int32_t sx = bx + MKGUI_TOOLBAR_SEP_W / 2;
					draw_vline(buf, bw, bh, sx, ry + 4, rh - 8, ctx->theme.widget_border);
					bx += MKGUI_TOOLBAR_SEP_W;
				}
				int32_t icon_idx = btn->icon[0] ? icon_resolve(btn->icon) : -1;
				int32_t tw = text_width(ctx, btn->label);
				int32_t icon_iw = icon_idx >= 0 ? MKGUI_ICON_SIZE + 4 : 0;
				int32_t content_w = icon_iw + tw;
				int32_t btn_w = content_w + 12;
				if(btn_w < MKGUI_TOOLBAR_BTN_W) {
					btn_w = MKGUI_TOOLBAR_BTN_W;
				}
				int32_t btn_y = ry + 2;
				int32_t btn_h = rh - 4;
				draw_rect_fill(buf, bw, bh, bx, btn_y, btn_w, btn_h, ctx->theme.header_bg);
				int32_t ccx = bx + (btn_w - content_w) / 2;
				if(icon_idx >= 0) {
					int32_t iy = btn_y + (btn_h - MKGUI_ICON_SIZE) / 2;
					draw_icon(buf, bw, bh, &icons[icon_idx], ccx, iy, bx, btn_y, bx + btn_w, btn_y + btn_h);
					ccx += MKGUI_ICON_SIZE + 4;
				}
				if(btn->label[0]) {
					int32_t ty = btn_y + (btn_h - ctx->font_height) / 2;
					push_text_clip(ccx, ty, btn->label, ctx->theme.text, bx, btn_y, bx + btn_w, btn_y + btn_h);
				}
				bx += btn_w + 2;
			}
		} break;

		case MKGUI_STATUSBAR: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, ctx->theme.header_bg);
			draw_hline(buf, bw, bh, rx, ry, rw, ctx->theme.widget_border);
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 4, ty, ew->label[0] ? ew->label : "Status", ctx->theme.text, rx, ry, rx + rw, ry + rh);
		} break;

		case MKGUI_MENU: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, ctx->theme.menu_bg);
			int32_t mx = rx;
			for(uint32_t i = 0; i < ed.widget_count; ++i) {
				struct ed_widget *mi = &ed.widgets[i];
				if(mi->type != MKGUI_MENUITEM || mi->parent_id != ew->id) {
					continue;
				}
				int32_t iw = text_width(ctx, mi->label) + 16;
				draw_rect_fill(buf, bw, bh, mx, ry, iw, rh, ctx->theme.menu_bg);
				int32_t ty = ry + (rh - ctx->font_height) / 2;
				push_text_clip(mx + 8, ty, mi->label, ctx->theme.text, mx, ry, mx + iw, ry + rh);
				mx += iw;
			}
		} break;

		case MKGUI_HSPLIT: {
			int32_t split_y = ry + rh / 2;
			draw_rect_fill(buf, bw, bh, rx, split_y, rw, MKGUI_SPLIT_THICK, ctx->theme.splitter);
		} break;

		case MKGUI_VSPLIT: {
			int32_t split_x = rx + rw / 2;
			draw_rect_fill(buf, bw, bh, split_x, ry, MKGUI_SPLIT_THICK, rh, ctx->theme.splitter);
		} break;

		case MKGUI_SCROLLBAR: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, ctx->theme.scrollbar_bg);
			if(rw > rh) {
				int32_t thumb_w = rw / 3;
				draw_rounded_rect_fill(buf, bw, bh, rx + thumb_w / 2, ry + 2, thumb_w, rh - 4, ctx->theme.scrollbar_thumb, 3);
			} else {
				int32_t thumb_h = rh / 3;
				draw_rounded_rect_fill(buf, bw, bh, rx + 2, ry + thumb_h / 2, rw - 4, thumb_h, ctx->theme.scrollbar_thumb, 3);
			}
		} break;

		case MKGUI_SPINNER: {
			int32_t sz = rw < rh ? rw : rh;
			int32_t cx = rx + rw / 2;
			int32_t cy = ry + rh / 2;
			int32_t r = sz / 2 - 2;
			if(r > 0) {
				draw_aa_circle_ring(buf, bw, bh, cx, cy, r, r - 2, ctx->theme.bg, ctx->theme.widget_border);
				draw_aa_circle_fill(buf, bw, bh, cx, cy - r + 1, 2, ctx->theme.accent);
			}
		} break;

		case MKGUI_IMAGE: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, ctx->theme.input_bg);
			draw_rect_border(buf, bw, bh, rx, ry, rw, rh, ctx->theme.widget_border);
			draw_aa_line(buf, bw, bh, rx, ry, rx + rw - 1, ry + rh - 1, ctx->theme.widget_border, 1);
			draw_aa_line(buf, bw, bh, rx + rw - 1, ry, rx, ry + rh - 1, ctx->theme.widget_border, 1);
		} break;

		case MKGUI_GLVIEW: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, 0xFF1A1A2E);
			draw_rect_border(buf, bw, bh, rx, ry, rw, rh, ctx->theme.widget_border);
			int32_t ty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 4, ty, "GLView", ctx->theme.text_disabled, rx, ry, rx + rw, ry + rh);
		} break;

		case MKGUI_CANVAS: {
			draw_rect_fill(buf, bw, bh, rx, ry, rw, rh, 0xFF2A2A2A);
			draw_rect_border(buf, bw, bh, rx, ry, rw, rh, ctx->theme.widget_border);
			int32_t cty = ry + (rh - ctx->font_height) / 2;
			push_text_clip(rx + 4, cty, "Canvas", ctx->theme.text_disabled, rx, ry, rx + rw, ry + rh);
		} break;

		default: break;
	}
}

// ---------------------------------------------------------------------------
// Canvas rendering (render callback)
// ---------------------------------------------------------------------------

// [=]===^=[ ed_render_canvas ]===================================[=]
static void ed_render_canvas(struct mkgui_ctx *ctx, uint32_t id, uint32_t *pixels, int32_t cx, int32_t cy, int32_t cw, int32_t ch, void *userdata) {
	(void)id;
	(void)pixels;
	(void)userdata;

	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, cx, cy, cw, ch, 0xFF3A3A3A);

	int32_t win_x = cx + (cw - ed.canvas_w) / 2;
	int32_t win_y = cy + (ch - ed.canvas_h) / 2;
	ed_win_x = win_x;
	ed_win_y = win_y;

	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, win_x, win_y, ed.canvas_w, ed.canvas_h, ctx->theme.bg);
	draw_rect_border(ctx->pixels, ctx->win_w, ctx->win_h, win_x, win_y, ed.canvas_w, ed.canvas_h, 0xFF555555);

	if(ed.grid_size >= 4) {
		for(int32_t gy = 0; gy < ed.canvas_h; gy += ed.grid_size) {
			for(int32_t gx = 0; gx < ed.canvas_w; gx += ed.grid_size) {
				int32_t px = win_x + gx;
				int32_t py = win_y + gy;
				if(px >= cx && px < cx + cw && py >= cy && py < cy + ch) {
					if(px >= 0 && px < ctx->win_w && py >= 0 && py < ctx->win_h) {
						ctx->pixels[py * ctx->win_w + px] = 0xFF4A4A4A;
					}
				}
			}
		}
	}

	// Compute ed_rects from editor widget positions
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *ew = &ed.widgets[i];
		if(ew->type == MKGUI_WINDOW) {
			ed_rects[i].x = win_x;
			ed_rects[i].y = win_y;
			ed_rects[i].w = ed.canvas_w;
			ed_rects[i].h = ed.canvas_h;
		} else {
			ed_rects[i].x = win_x + ew->x;
			ed_rects[i].y = win_y + ew->y;
			ed_rects[i].w = ew->w;
			ed_rects[i].h = ew->h;
		}
	}

	// Auto-layout pass for VBOX/HBOX/FORM children
	for(uint32_t pass = 0; pass < 4; ++pass) {
		for(uint32_t i = 0; i < ed.widget_count; ++i) {
			struct ed_widget *ew = &ed.widgets[i];
			if(ew->type == MKGUI_WINDOW) {
				continue;
			}
			int32_t pidx = -1;
			for(uint32_t j = 0; j < ed.widget_count; ++j) {
				if(ed.widgets[j].id == ew->parent_id) {
					pidx = (int32_t)j;
					break;
				}
			}
			if(pidx < 0) {
				continue;
			}
			struct ed_widget *parent = &ed.widgets[pidx];
			if(parent->type != MKGUI_VBOX && parent->type != MKGUI_HBOX && parent->type != MKGUI_FORM) {
				continue;
			}

			int32_t px = ed_rects[pidx].x;
			int32_t py = ed_rects[pidx].y;
			int32_t pw = ed_rects[pidx].w;
			int32_t ph = ed_rects[pidx].h;

			if(parent->flags & MKGUI_PANEL_BORDER) {
				px += MKGUI_BOX_PAD;
				py += MKGUI_BOX_PAD;
				pw -= MKGUI_BOX_PAD * 2;
				ph -= MKGUI_BOX_PAD * 2;
			}

			uint32_t child_count = 0;
			for(uint32_t j = 0; j < ed.widget_count; ++j) {
				if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
					++child_count;
				}
			}

			if(parent->type == MKGUI_VBOX) {
				int32_t fixed_total = 0;
				uint32_t flex_count = 0;
				for(uint32_t j = 0; j < ed.widget_count; ++j) {
					if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
						if(ed.widgets[j].h > 0) {
							fixed_total += ed.widgets[j].h;
						} else {
							++flex_count;
						}
					}
				}
				int32_t gap_total = child_count > 1 ? (int32_t)(child_count - 1) * MKGUI_BOX_GAP : 0;
				int32_t remaining = ph - fixed_total - gap_total;
				if(remaining < 0) {
					remaining = 0;
				}
				int32_t flex_h = flex_count > 0 ? remaining / (int32_t)flex_count : 0;

				int32_t lay_y = py;
				for(uint32_t j = 0; j < ed.widget_count; ++j) {
					if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
						int32_t child_h = ed.widgets[j].h > 0 ? ed.widgets[j].h : flex_h;
						if(j == i) {
							ed_rects[i].x = px;
							ed_rects[i].y = lay_y;
							ed_rects[i].w = pw;
							ed_rects[i].h = child_h;
							break;
						}
						lay_y += child_h + MKGUI_BOX_GAP;
					}
				}

			} else if(parent->type == MKGUI_HBOX) {
				int32_t fixed_total = 0;
				uint32_t flex_count = 0;
				for(uint32_t j = 0; j < ed.widget_count; ++j) {
					if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
						if(ed.widgets[j].w > 0) {
							fixed_total += ed.widgets[j].w;
						} else {
							++flex_count;
						}
					}
				}
				int32_t gap_total = child_count > 1 ? (int32_t)(child_count - 1) * MKGUI_BOX_GAP : 0;
				int32_t remaining = pw - fixed_total - gap_total;
				if(remaining < 0) {
					remaining = 0;
				}
				int32_t flex_w = flex_count > 0 ? remaining / (int32_t)flex_count : 0;

				int32_t lay_x = px;
				for(uint32_t j = 0; j < ed.widget_count; ++j) {
					if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
						int32_t child_w = ed.widgets[j].w > 0 ? ed.widgets[j].w : flex_w;
						if(j == i) {
							ed_rects[i].x = lay_x;
							ed_rects[i].y = py;
							ed_rects[i].w = child_w;
							ed_rects[i].h = ph;
							break;
						}
						lay_x += child_w + MKGUI_BOX_GAP;
					}
				}

			} else {
				int32_t label_w = 0;
				uint32_t pair_idx = 0;
				for(uint32_t j = 0; j < ed.widget_count; ++j) {
					if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
						if((pair_idx & 1) == 0) {
							int32_t tw = text_width(ctx, ed.widgets[j].label) + 8;
							if(tw > label_w) {
								label_w = tw;
							}
						}
						++pair_idx;
					}
				}

				pair_idx = 0;
				for(uint32_t j = 0; j < ed.widget_count; ++j) {
					if(ed.widgets[j].parent_id == parent->id && j != (uint32_t)pidx && !(ed.widgets[j].flags & MKGUI_HIDDEN)) {
						int32_t row = (int32_t)(pair_idx / 2);
						int32_t row_h = 24;
						uint32_t is_label = (pair_idx & 1) == 0;
						if(j == i) {
							if(is_label) {
								ed_rects[i].x = px;
								ed_rects[i].y = py + row * (row_h + MKGUI_BOX_GAP);
								ed_rects[i].w = label_w;
								ed_rects[i].h = row_h;
							} else {
								ed_rects[i].x = px + label_w;
								ed_rects[i].y = py + row * (row_h + MKGUI_BOX_GAP);
								ed_rects[i].w = pw - label_w;
								ed_rects[i].h = row_h;
							}
							break;
						}
						++pair_idx;
					}
				}
			}
		}
	}

	// Anchor pass
	for(uint32_t pass = 0; pass < 4; ++pass) {
		for(uint32_t i = 0; i < ed.widget_count; ++i) {
			struct ed_widget *ew = &ed.widgets[i];
			if(ew->type == MKGUI_WINDOW) {
				continue;
			}
			uint32_t has_anchor = ew->flags & (MKGUI_ANCHOR_LEFT | MKGUI_ANCHOR_TOP | MKGUI_ANCHOR_RIGHT | MKGUI_ANCHOR_BOTTOM);
			if(!has_anchor) {
				continue;
			}
			int32_t pidx = -1;
			for(uint32_t j = 0; j < ed.widget_count; ++j) {
				if(ed.widgets[j].id == ew->parent_id) {
					pidx = (int32_t)j;
					break;
				}
			}
			if(pidx < 0) {
				continue;
			}
			struct ed_widget *parent = &ed.widgets[pidx];
			if(parent->type == MKGUI_VBOX || parent->type == MKGUI_HBOX || parent->type == MKGUI_FORM) {
				continue;
			}

			int32_t ppx = ed_rects[pidx].x;
			int32_t ppy = ed_rects[pidx].y;
			int32_t ppw = ed_rects[pidx].w;
			int32_t pph = ed_rects[pidx].h;

			if(parent->type == MKGUI_TAB) {
				ppx += 2;
				ppy += MKGUI_TAB_HEIGHT + 2;
				ppw -= 4;
				pph -= MKGUI_TAB_HEIGHT + 4;
			}
			if(parent->type == MKGUI_GROUP) {
				int32_t gtop = ctx->font_height + 4;
				int32_t gpad = 6;
				ppx += gpad;
				ppy += gtop;
				ppw -= gpad * 2;
				pph -= gtop + gpad;
			}

			int32_t ox = ed_rects[i].x - ppx;
			int32_t oy = ed_rects[i].y - ppy;
			int32_t ow = ed_rects[i].w;
			int32_t oh = ed_rects[i].h;

			int32_t margin_r = ppw - ox - ow;
			if(margin_r < 0) {
				margin_r = 0;
			}
			int32_t margin_b = pph - oy - oh;
			if(margin_b < 0) {
				margin_b = 0;
			}

			if((ew->flags & MKGUI_ANCHOR_LEFT) && (ew->flags & MKGUI_ANCHOR_RIGHT)) {
				ed_rects[i].x = ppx + ox;
				ed_rects[i].w = ppw - ox - margin_r;
			} else if(ew->flags & MKGUI_ANCHOR_RIGHT) {
				ed_rects[i].x = ppx + ppw - ow - margin_r;
			}

			if((ew->flags & MKGUI_ANCHOR_TOP) && (ew->flags & MKGUI_ANCHOR_BOTTOM)) {
				ed_rects[i].y = ppy + oy;
				ed_rects[i].h = pph - oy - margin_b;
			} else if(ew->flags & MKGUI_ANCHOR_BOTTOM) {
				ed_rects[i].y = ppy + pph - oh - margin_b;
			}
		}
	}

	// Render design-time widget representations
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_WINDOW || ed.widgets[i].type == MKGUI_TAB || ed.widgets[i].type == MKGUI_MENUITEM) {
			continue;
		}
		if(!ed_is_tab_child_visible(i)) {
			continue;
		}
		if(ed_rects[i].w <= 0 || ed_rects[i].h <= 0) {
			continue;
		}
		ed_draw_widget(ctx, i);
	}

	// Draw dashed outlines for invisible containers
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		uint32_t t = ed.widgets[i].type;
		uint32_t fl = ed.widgets[i].flags;
		uint32_t needs_outline = 0;
		if(t == MKGUI_VBOX || t == MKGUI_HBOX || t == MKGUI_FORM) {
			if(!(fl & MKGUI_PANEL_BORDER)) {
				needs_outline = 1;
			}
		} else if(t == MKGUI_TABS || t == MKGUI_HSPLIT || t == MKGUI_VSPLIT) {
			needs_outline = 1;
		} else if(t == MKGUI_PANEL) {
			if(!(fl & (MKGUI_PANEL_BORDER | MKGUI_PANEL_SUNKEN))) {
				needs_outline = 1;
			}
		}
		if(needs_outline) {
			draw_rect_dashed(ctx->pixels, ctx->win_w, ctx->win_h, ed_rects[i].x, ed_rects[i].y, ed_rects[i].w, ed_rects[i].h, 0xFF666666, 4);
		}
	}

	// Selection handles on top
	if(ed.selected >= 0 && (uint32_t)ed.selected < ed.widget_count) {
		int32_t wx = ed_rects[ed.selected].x;
		int32_t wy = ed_rects[ed.selected].y;
		int32_t ww = ed_rects[ed.selected].w;
		int32_t wh = ed_rects[ed.selected].h;

		draw_rect_border(ctx->pixels, ctx->win_w, ctx->win_h, wx - 1, wy - 1, ww + 2, wh + 2, 0xFF007ACC);

		int32_t hx[] = { wx, wx + ww / 2, wx + ww, wx + ww, wx + ww, wx + ww / 2, wx, wx };
		int32_t hy[] = { wy, wy, wy, wy + wh / 2, wy + wh, wy + wh, wy + wh, wy + wh / 2 };
		for(int32_t j = 0; j < 8; ++j) {
			draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, hx[j] - 3, hy[j] - 3, 6, 6, 0xFF007ACC);
		}
	}

	uint32_t hc = 0xFF888888;
	int32_t hs = 4;
	int32_t mx = win_x + ed.canvas_w / 2;
	int32_t my = win_y + ed.canvas_h / 2;
	int32_t rx = win_x + ed.canvas_w;
	int32_t by = win_y + ed.canvas_h;
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, mx - hs, win_y - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, mx - hs, by - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, win_x - hs, my - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, rx - hs, my - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, win_x - hs, win_y - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, rx - hs, win_y - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, win_x - hs, by - hs, hs * 2, hs * 2, hc);
	draw_rect_fill(ctx->pixels, ctx->win_w, ctx->win_h, rx - hs, by - hs, hs * 2, hs * 2, hc);

	if(ed.placement_type) {
		const char *placing = ed_type_name(ed.placement_type);
		char buf[64];
		snprintf(buf, sizeof(buf), "Placing: %s (click canvas, Esc to cancel)", placing);
		push_text(cx + 4, cy + 4, buf, 0xFFFFFF00);
	}

	char size_buf[32];
	snprintf(size_buf, sizeof(size_buf), "%dx%d", ed.canvas_w, ed.canvas_h);
	push_text(win_x + 2, by + 4, size_buf, 0xFF888888);
}

// ---------------------------------------------------------------------------
// Treeview sync
// ---------------------------------------------------------------------------

// [=]===^=[ ed_sync_tree ]=======================================[=]
static void ed_sync_tree(struct mkgui_ctx *ctx) {
	mkgui_treeview_setup(ctx, ED_TREE);
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *w = &ed.widgets[i];
		char buf[128];
		snprintf(buf, sizeof(buf), "%s: %s", ed_type_name(w->type), w->id_name);
		uint32_t parent_node = 0;
		if(w->parent_id != 0) {
			parent_node = w->parent_id;
		}
		mkgui_treeview_add(ctx, ED_TREE, w->id, parent_node, buf);
	}

	struct mkgui_treeview_data *tv = find_treeview_data(ctx, ED_TREE);
	if(tv) {
		for(uint32_t j = 0; j < tv->node_count; ++j) {
			tv->nodes[j].expanded = 1;
		}
		if(ed.selected >= 0 && (uint32_t)ed.selected < ed.widget_count) {
			tv->selected_node = (int32_t)ed.widgets[ed.selected].id;
		}
	}

	dirty_all(ctx);
}

// [=]===^=[ ed_find_menu_root ]===================================[=]
static uint32_t ed_find_menu_root(uint32_t widget_idx) {
	struct ed_widget *w = &ed.widgets[widget_idx];
	if(w->type == MKGUI_MENU) {
		return w->id;
	}
	uint32_t pid = w->parent_id;
	for(uint32_t depth = 0; depth < 32; ++depth) {
		int32_t idx = ed_find_widget(pid);
		if(idx < 0) {
			break;
		}
		if(ed.widgets[idx].type == MKGUI_MENU) {
			return ed.widgets[idx].id;
		}
		pid = ed.widgets[idx].parent_id;
	}
	return 0;
}

// [=]===^=[ ed_sync_menu_tree ]===================================[=]
static void ed_sync_menu_tree(struct mkgui_ctx *ctx) {
	struct mkgui_widget *tw = find_widget(ctx, ED_MENU_TREE);
	if(!tw) {
		return;
	}

	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		tw->flags |= MKGUI_HIDDEN;
		return;
	}

	struct ed_widget *sel = &ed.widgets[ed.selected];
	if(sel->type != MKGUI_MENU && sel->type != MKGUI_MENUITEM) {
		tw->flags |= MKGUI_HIDDEN;
		return;
	}

	uint32_t menu_id = ed_find_menu_root((uint32_t)ed.selected);
	if(!menu_id) {
		tw->flags |= MKGUI_HIDDEN;
		return;
	}

	tw->flags &= ~MKGUI_HIDDEN;

	mkgui_treeview_setup(ctx, ED_MENU_TREE);

	int32_t menu_idx = ed_find_widget(menu_id);
	if(menu_idx >= 0) {
		struct ed_widget *mw = &ed.widgets[menu_idx];
		char buf[128];
		snprintf(buf, sizeof(buf), "%s: %s", ed_type_name(mw->type), mw->id_name);
		mkgui_treeview_add(ctx, ED_MENU_TREE, mw->id, 0, buf);
	}

	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *w = &ed.widgets[i];
		if(w->type == MKGUI_MENUITEM && ed_is_descendant(i, menu_id)) {
			char buf[128];
			snprintf(buf, sizeof(buf), "%s: %s", ed_type_name(w->type), w->label[0] ? w->label : w->id_name);
			mkgui_treeview_add(ctx, ED_MENU_TREE, w->id, w->parent_id, buf);
		}
	}

	struct mkgui_treeview_data *tv = find_treeview_data(ctx, ED_MENU_TREE);
	if(tv) {
		for(uint32_t j = 0; j < tv->node_count; ++j) {
			tv->nodes[j].expanded = 1;
		}
		tv->selected_node = (int32_t)sel->id;
	}

	dirty_all(ctx);
}

// ---------------------------------------------------------------------------
// Property panel sync
// ---------------------------------------------------------------------------

// [=]===^=[ ed_sync_parent_dropdown ]=============================[=]
static void ed_sync_parent_dropdown(struct mkgui_ctx *ctx) {
	const char *items[ED_MAX_WIDGETS];
	static char item_bufs[ED_MAX_WIDGETS][80];
	uint32_t count = 0;

	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *ew = &ed.widgets[i];
		if(ew->type == MKGUI_WINDOW || ew->type == MKGUI_TABS || ew->type == MKGUI_TAB ||
		   ew->type == MKGUI_HSPLIT || ew->type == MKGUI_VSPLIT || ew->type == MKGUI_GROUP || ew->type == MKGUI_PANEL ||
		   ew->type == MKGUI_VBOX || ew->type == MKGUI_HBOX || ew->type == MKGUI_FORM) {
			snprintf(item_bufs[count], sizeof(item_bufs[count]), "%u: %s (%s)", ew->id, ew->id_name[0] ? ew->id_name : ew->label, ed_type_name(ew->type));
			items[count] = item_bufs[count];
			++count;
		}
	}

	if(count == 0) {
		return;
	}

	mkgui_dropdown_setup(ctx, ED_PROP_PARENT_DRP, items, count);

	if(ed.selected >= 0 && (uint32_t)ed.selected < ed.widget_count) {
		uint32_t pid = ed.widgets[ed.selected].parent_id;
		uint32_t sel_idx = 0;
		uint32_t j = 0;
		for(uint32_t i = 0; i < ed.widget_count; ++i) {
			struct ed_widget *ew = &ed.widgets[i];
			if(ew->type == MKGUI_WINDOW || ew->type == MKGUI_TABS || ew->type == MKGUI_TAB ||
			   ew->type == MKGUI_HSPLIT || ew->type == MKGUI_VSPLIT ||
			   ew->type == MKGUI_MENU || ew->type == MKGUI_MENUITEM || ew->type == MKGUI_GROUP || ew->type == MKGUI_PANEL ||
			   ew->type == MKGUI_VBOX || ew->type == MKGUI_HBOX || ew->type == MKGUI_FORM) {
				if(ew->id == pid) {
					sel_idx = j;
				}
				++j;
			}
		}
		struct mkgui_dropdown_data *dd = find_dropdown_data(ctx, ED_PROP_PARENT_DRP);
		if(dd) {
			dd->selected = (int32_t)sel_idx;
		}
	}
}

// [=]===^=[ ed_apply_parent_dropdown ]============================[=]
static void ed_apply_parent_dropdown(struct mkgui_ctx *ctx) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}

	struct mkgui_dropdown_data *dd = find_dropdown_data(ctx, ED_PROP_PARENT_DRP);
	if(!dd || dd->selected < 0) {
		return;
	}

	uint32_t j = 0;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *ew = &ed.widgets[i];
		if(ew->type == MKGUI_WINDOW || ew->type == MKGUI_TABS || ew->type == MKGUI_TAB ||
		   ew->type == MKGUI_HSPLIT || ew->type == MKGUI_VSPLIT ||
		   ew->type == MKGUI_GROUP || ew->type == MKGUI_PANEL ||
		   ew->type == MKGUI_VBOX || ew->type == MKGUI_HBOX || ew->type == MKGUI_FORM) {
			if(j == (uint32_t)dd->selected) {
				ed.widgets[ed.selected].parent_id = ew->id;
				ed_sync_tree(ctx);
				dirty_all(ctx);
				return;
			}
			++j;
		}
	}
}

// [=]===^=[ ed_update_prop_group_h ]=============================[=]
static void ed_update_prop_group_h(struct mkgui_ctx *ctx) {
	int32_t h = ED_PROP_GROUP_H;
	struct mkgui_widget *w;
	w = find_widget(ctx, ED_PROP_BTN_HBOX);
	if(w && !(w->flags & MKGUI_HIDDEN)) {
		h += 22 + MKGUI_BOX_GAP;
	}
	w = find_widget(ctx, ED_MENU_TREE);
	if(w && !(w->flags & MKGUI_HIDDEN)) {
		h += 200 + MKGUI_BOX_GAP;
	}
	w = find_widget(ctx, ED_PROP_GROUP);
	if(w) {
		w->h = h;
	}
}

// [=]===^=[ ed_sync_props ]======================================[=]
static void ed_sync_props(struct mkgui_ctx *ctx) {
	struct ed_widget *w = NULL;
	uint32_t vis = 0;
	if(ed.selected >= 0 && (uint32_t)ed.selected < ed.widget_count) {
		w = &ed.widgets[ed.selected];
		vis = ed_compute_vis_mask(w);
	}

	uint32_t btn_hbox_visible = 0;
	for(uint32_t i = 0; i < ED_PROP_COUNT; ++i) {
		struct ed_prop_desc *p = &ed_props[i];
		uint32_t show = w && ed_prop_visible(p, vis);
		ed_set_widget_vis(ctx, p->widget_id, show);
		ed_set_widget_vis(ctx, p->label_id, show);
		ed_set_widget_vis(ctx, p->widget_id2, show);
		ed_set_widget_vis(ctx, p->label_id2, show);
		if(show && w) {
			ed_sync_prop_value(ctx, p, w);
			if(p->kind == ED_PK_ACTION) {
				btn_hbox_visible = 1;
			}
		}
	}
	ed_set_widget_vis(ctx, ED_PROP_BTN_HBOX, btn_hbox_visible);

	if(!w) {
		mkgui_label_set(ctx, ED_PROP_TYPE_VAL, "(none)");
	}

	ed_sync_parent_dropdown(ctx);
	ed_sync_menu_tree(ctx);
	ed_update_prop_group_h(ctx);
	dirty_all(ctx);
}

// [=]===^=[ ed_read_props ]======================================[=]
static void ed_read_props(struct mkgui_ctx *ctx) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}
	struct ed_widget *w = &ed.widgets[ed.selected];
	w->flags = 0;
	for(uint32_t i = 0; i < ED_PROP_COUNT; ++i) {
		ed_read_prop_value(ctx, &ed_props[i], w);
	}
	dirty_all(ctx);
}

// ---------------------------------------------------------------------------
// Tab / menu management
// ---------------------------------------------------------------------------

// [=]===^=[ ed_add_tab_to_tabs ]==================================[=]
static void ed_add_tab_to_tabs(struct mkgui_ctx *ctx) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}
	struct ed_widget *tabs_w = &ed.widgets[ed.selected];
	if(tabs_w->type != MKGUI_TABS || ed.widget_count >= ED_MAX_WIDGETS) {
		return;
	}

	ed_push_undo();

	uint32_t tabs_id = tabs_w->id;
	uint32_t tab_num = 0;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_TAB && ed.widgets[i].parent_id == tabs_id) {
			++tab_num;
		}
	}

	uint32_t pos = ed_insert_child_after(tabs_id);
	struct ed_widget *tab = &ed.widgets[pos];
	tab->type = MKGUI_TAB;
	tab->id = ed.next_id++;
	tab->parent_id = tabs_id;
	snprintf(tab->label, sizeof(tab->label), "Tab %u", tab_num + 1);
	tab->tab_order = pos;
	ed_gen_id_name(tab);

	ed_set_active_tab(tabs_id, tab->id);
	ed.selected = ed_find_widget(tabs_id);
	ed_sync_tree(ctx);
	ed_sync_props(ctx);
}

// [=]===^=[ ed_remove_tab_from_tabs ]=============================[=]
static void ed_remove_tab_from_tabs(struct mkgui_ctx *ctx) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}
	struct ed_widget *tabs_w = &ed.widgets[ed.selected];
	if(tabs_w->type != MKGUI_TABS) {
		return;
	}

	uint32_t active = ed_get_active_tab(tabs_w->id);
	if(!active) {
		return;
	}

	uint32_t tab_count = 0;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_TAB && ed.widgets[i].parent_id == tabs_w->id) {
			++tab_count;
		}
	}
	if(tab_count <= 1) {
		return;
	}

	ed_push_undo();

	ed_delete_widget_tree(active);

	uint32_t new_active = 0;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_TAB && ed.widgets[i].parent_id == tabs_w->id) {
			new_active = ed.widgets[i].id;
			break;
		}
	}
	ed_set_active_tab(tabs_w->id, new_active);

	ed.selected = ed_find_widget(tabs_w->id);
	ed_sync_tree(ctx);
	ed_sync_props(ctx);
}

// [=]===^=[ ed_add_menu_item ]====================================[=]
static void ed_add_menu_item(struct mkgui_ctx *ctx) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}
	struct ed_widget *parent_w = &ed.widgets[ed.selected];
	if((parent_w->type != MKGUI_MENU && parent_w->type != MKGUI_MENUITEM) || ed.widget_count >= ED_MAX_WIDGETS) {
		return;
	}

	ed_push_undo();

	uint32_t parent_id = parent_w->id;
	uint32_t pos = ed_insert_child_after(parent_id);
	struct ed_widget *item = &ed.widgets[pos];
	item->type = MKGUI_MENUITEM;
	item->id = ed.next_id++;
	item->parent_id = parent_id;
	snprintf(item->label, sizeof(item->label), "Item");
	item->tab_order = pos;
	ed_gen_id_name(item);

	ed.selected = ed_find_widget(parent_id);
	ed_sync_tree(ctx);
	ed_sync_props(ctx);
}

// [=]===^=[ ed_remove_menu_item ]=================================[=]
static void ed_remove_menu_item(struct mkgui_ctx *ctx) {
	if(ed.selected < 0 || (uint32_t)ed.selected >= ed.widget_count) {
		return;
	}
	struct ed_widget *sel = &ed.widgets[ed.selected];
	if(sel->type != MKGUI_MENU && sel->type != MKGUI_MENUITEM) {
		return;
	}

	if(sel->type == MKGUI_MENUITEM) {
		ed_push_undo();
		uint32_t parent_id = sel->parent_id;
		ed_delete_widget_tree(sel->id);
		ed.selected = ed_find_widget(parent_id);
		ed_sync_tree(ctx);
		ed_sync_props(ctx);
		return;
	}

	int32_t last_item = -1;
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		if(ed.widgets[i].type == MKGUI_MENUITEM && ed.widgets[i].parent_id == sel->id) {
			last_item = (int32_t)i;
		}
	}
	if(last_item < 0) {
		return;
	}

	ed_push_undo();

	uint32_t del_id = ed.widgets[last_item].id;
	ed_delete_widget_tree(del_id);

	ed.selected = ed_find_widget(sel->id);
	ed_sync_tree(ctx);
	ed_sync_props(ctx);
}

// ---------------------------------------------------------------------------
// Code generation
// ---------------------------------------------------------------------------

// [=]===^=[ ed_generate_code ]===================================[=]
static void ed_generate_code(void) {
	FILE *fh = fopen("gui_ids.h", "w");
	FILE *fc = fopen("gui_layout.c", "w");
	if(!fh || !fc) {
		if(fh) {
			fclose(fh);
		}
		if(fc) {
			fclose(fc);
		}
		return;
	}

	fprintf(fh, "// Generated by mkgui-editor -- do not edit by hand\n");
	fprintf(fh, "#ifndef GUI_IDS_H\n");
	fprintf(fh, "#define GUI_IDS_H\n\n");
	fprintf(fh, "enum {\n");
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		fprintf(fh, "\t%s = %u,\n", ed.widgets[i].id_name, ed.widgets[i].id);
	}
	fprintf(fh, "};\n\n");
	fprintf(fh, "#endif\n");
	fclose(fh);

	fprintf(fc, "// Generated by mkgui-editor -- do not edit by hand\n\n");
	fprintf(fc, "#include \"gui_ids.h\"\n\n");
	fprintf(fc, "static struct mkgui_widget gui_widgets[] = {\n");
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *w = &ed.widgets[i];
		int32_t lx, ly, lw, lh;
		ed_convert_to_layout(i, &lx, &ly, &lw, &lh);
		fprintf(fc, "\t{ %u, %s, \"%s\", \"%s\", %u, %d, %d, %d, %d, 0x%X },\n",
			w->type, w->id_name, w->label, w->icon, w->parent_id,
			lx, ly, lw, lh, w->flags);
	}
	fprintf(fc, "};\n\n");
	fprintf(fc, "static uint32_t gui_widget_count = sizeof(gui_widgets) / sizeof(gui_widgets[0]);\n");
	fclose(fc);

	printf("Generated gui_ids.h and gui_layout.c (%u widgets)\n", ed.widget_count);
}

// ---------------------------------------------------------------------------
// Test GUI
// ---------------------------------------------------------------------------

// [=]===^=[ ed_test_gui ]========================================[=]
static void ed_test_gui(void) {
	if(ed.widget_count == 0) {
		return;
	}

	struct mkgui_widget test_widgets[ED_MAX_WIDGETS];
	for(uint32_t i = 0; i < ed.widget_count; ++i) {
		struct ed_widget *ew = &ed.widgets[i];
		struct mkgui_widget *tw = &test_widgets[i];
		tw->type = ew->type;
		tw->id = ew->id;
		size_t slen = strlen(ew->label);
		if(slen >= MKGUI_MAX_TEXT) {
			slen = MKGUI_MAX_TEXT - 1;
		}
		memcpy(tw->label, ew->label, slen);
		tw->label[slen] = '\0';
		tw->parent_id = ew->parent_id;
		memcpy(tw->icon, ew->icon, MKGUI_ICON_NAME_LEN);
		ed_convert_to_layout(i, &tw->x, &tw->y, &tw->w, &tw->h);
		tw->flags = ew->flags;
	}

	struct mkgui_ctx *test = mkgui_create(test_widgets, ed.widget_count);
	if(!test) {
		return;
	}


	struct mkgui_event ev;
	uint32_t running = 1;
	while(running) {
		while(mkgui_poll(test, &ev)) {
			if(ev.type == MKGUI_EVENT_CLOSE) {
				running = 0;
			}
		}
	}

	mkgui_destroy(test);
}

